+            .unwrap_or(0)
+    }
+
+    /// Average commit latency in microseconds, or 0 if no group commits.
+    #[must_use]
+    pub fn avg_commit_latency_us(&self) -> u64 {
+        self.commit_latency_us_total
+            .checked_div(self.group_commits_total)
+            .unwrap_or(0)
+    }
